def force_adverse(rec: dict) -> dict:
    bad = dict(rec)
    for k, v in rec.items():
        if k == "case_id":
            continue
        if isinstance(v, bool):
            bad[k] = (not v) if k not in ("secret_baked", "debug_shell", "shared_database", "infers_fraud", "compiler_in_runtime") else True
            if k in ("secret_baked", "debug_shell", "shared_database", "infers_fraud", "compiler_in_runtime", "pii_in_trace", "forbidden_tool_used"):
                bad[k] = True
            elif k in ("dependency_layer_reused", "digest_stable", "base_pinned", "runtime_secret", "config_declared", "private_network", "readiness_db", "sigterm_drains", "api_retries_db", "old_code_compatible", "ephemeral_reset", "backup_restored", "runtime_deps_locked", "logs_redacted", "lint", "types", "tests"):
                bad[k] = False
            return bad
        if isinstance(v, (int, float)) and v == 0 and "cve" in k:
            bad[k] = 1
            return bad
        if isinstance(v, (int, float)) and "uid" == k:
            bad[k] = 0
            return bad
    return {**bad, "uid": 0} if "uid" in bad else {**bad, "ok": False}

